import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const location = useLocation();
  const { getCartCount } = useCart();
  const { user, logout } = useAuth();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = async () => {
    await logout();
    window.location.href = '/';
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="navbar" role="navigation" aria-label="Main navigation">
      <div className="nav-inner">
        <Link to="/" className="nav-logo" aria-label="Nova Shop Home">
          Nova<span>.</span>
        </Link>
        <ul className={`nav-links ${menuOpen ? 'open' : ''}`} id="navLinks">
          <li><Link to="/" className={isActive('/') ? 'active' : ''}>Home</Link></li>
          <li><Link to="/products" className={isActive('/products') ? 'active' : ''}>Shop</Link></li>
          <li><Link to="/login" className={isActive('/login') ? 'active' : ''}>Account</Link></li>
          <li><Link to="/cart" className={isActive('/cart') ? 'active' : ''}>Cart</Link></li>
        </ul>
        <div className="nav-actions">
          <Link to="/cart" aria-label="Shopping cart">
            <button className="nav-cart-btn" aria-label="View cart">
              🛒
              <span className={`cart-count ${getCartCount() > 0 ? '' : 'hidden'}`} aria-live="polite">
                {getCartCount()}
              </span>
            </button>
          </Link>
          {user ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
              <span style={{ fontSize: '0.85rem' }}>Hi, {user.firstName}</span>
              <button className="btn btn-outline btn-sm" onClick={handleLogout}>Logout</button>
            </div>
          ) : (
            <Link to="/login" className="btn btn-primary btn-sm">Sign In</Link>
          )}
          <button 
            className="hamburger" 
            id="hamburger" 
            aria-label="Toggle menu" 
            aria-expanded={menuOpen}
            onClick={() => setMenuOpen(!menuOpen)}
          >
            <span></span><span></span><span></span>
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
